"use client";
import { useState } from "react";
import Link from "next/link";

export default function WaterPage() {
  const [insight, setInsight] = useState("Click a sector to generate efficiency insights.");
  const [loading, setLoading] = useState(false);

  const fetchWaterInsights = async (sector: string, percentage: string) => {
    setLoading(true);
    setInsight(`Analyzing ${sector} sector usage...`);
    try {
      const res = await fetch("/api/water-coach", {
        method: "POST",
        body: JSON.stringify({ sector, percentage }),
      });
      const data = await res.json();
      setInsight(data.insight || data.error);
    } catch (err) {
      setInsight("Failed to fetch insights.");
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-black text-white p-10">
      <Link href="/" className="text-gray-400 hover:text-white mb-6 inline-block">← Back to Home</Link>
      <h1 className="text-4xl font-bold text-blue-500 mb-6">Water Usage Statistics</h1>
      
      {/* Placeholder for your pie chart */}
      <div className="h-64 bg-gray-900 border border-gray-800 rounded-xl mb-6 flex items-center justify-center text-gray-500">
        [Sector-Wise Pie Chart Component Goes Here]
      </div>

      <div className="flex flex-wrap gap-4 mb-6">
        <button onClick={() => fetchWaterInsights("Agriculture", "70")} disabled={loading} className="bg-gray-800 border border-gray-700 hover:border-blue-500 hover:text-blue-400 px-6 py-3 rounded-lg transition-all disabled:opacity-50">Agriculture (70%)</button>
        <button onClick={() => fetchWaterInsights("Industry", "19")} disabled={loading} className="bg-gray-800 border border-gray-700 hover:border-blue-500 hover:text-blue-400 px-6 py-3 rounded-lg transition-all disabled:opacity-50">Industry (19%)</button>
        <button onClick={() => fetchWaterInsights("Domestic", "11")} disabled={loading} className="bg-gray-800 border border-gray-700 hover:border-blue-500 hover:text-blue-400 px-6 py-3 rounded-lg transition-all disabled:opacity-50">Domestic (11%)</button>
      </div>

      <div className="p-6 bg-blue-950/30 border border-blue-500/30 rounded-xl">
        <h3 className="font-bold text-blue-400 mb-2">✨ Gemini 2.5 Efficiency Protocol</h3>
        <p className="whitespace-pre-line leading-relaxed">{insight}</p>
      </div>
    </div>
  );
}